from dataclasses import dataclass, field
from typing import Any, Callable

@dataclass
class MockAPIFixture:
    """One scripted response for a specific tool call."""
    tool_name: str
    match_args: dict            # partial match: request args that must be present
    response: Any               # the value returned to the agent
    error: str | None = None    # if set, raise this error instead

class MockAPIEnvironment:
    """
    Registry of scripted tool responses.
    The agent calls env.call(tool_name, **kwargs) instead of the real API.
    """
    def __init__(self, fixtures: list[MockAPIFixture]):
        self.fixtures = fixtures
        self.call_log: list[dict] = []

    def _matches(self, fixture: MockAPIFixture, kwargs: dict) -> bool:
        return all(kwargs.get(k) == v for k, v in fixture.match_args.items())

    def call(self, tool_name: str, **kwargs) -> Any:
        self.call_log.append({"tool": tool_name, "args": kwargs})
        for fix in self.fixtures:
            if fix.tool_name == tool_name and self._matches(fix, kwargs):
                if fix.error:
                    raise RuntimeError(fix.error)
                return fix.response
        raise KeyError(f"No fixture matched: {tool_name}({kwargs})")

    def assert_called(self, tool_name: str, times: int | None = None) -> None:
        calls = [c for c in self.call_log if c["tool"] == tool_name]
        if times is not None and len(calls) != times:
            raise AssertionError(
                f"Expected {tool_name} called {times}x, got {len(calls)}x"
            )
        if not calls:
            raise AssertionError(f"{tool_name} was never called")

# Example: mock for a customer lookup + order refund API
env = MockAPIEnvironment([
    MockAPIFixture(
        tool_name="lookup_customer",
        match_args={"customer_id": "C-001"},
        response={"name": "Alice", "tier": "premium", "orders": ["ORD-123"]},
    ),
    MockAPIFixture(
        tool_name="issue_refund",
        match_args={"order_id": "ORD-123"},
        response={"status": "ok", "refund_id": "REF-456", "amount_usd": 49.99},
    ),
    MockAPIFixture(
        tool_name="lookup_customer",
        match_args={"customer_id": "C-BAD"},
        response=None,
        error="Customer not found",
    ),
])

import tempfile, shutil, os, json
from contextlib import contextmanager

@contextmanager
def isolated_filesystem(seed_files: dict[str, str] | None = None):
    """
    Context manager that creates a temp directory pre-seeded with files,
    yields the path, and deletes everything on exit.

    seed_files: {relative_path: content}
    """
    tmpdir = tempfile.mkdtemp(prefix="sim_eval_")
    try:
        if seed_files:
            for rel_path, content in seed_files.items():
                full = os.path.join(tmpdir, rel_path)
                os.makedirs(os.path.dirname(full), exist_ok=True)
                with open(full, "w") as f:
                    f.write(content)
        yield tmpdir
    finally:
        shutil.rmtree(tmpdir, ignore_errors=True)

@contextmanager
def seeded_db(initial_records: list[dict]):
    """
    In-memory dict simulating a database, seeded with initial records.
    Agents call db.get(), db.put(), db.delete() instead of a real DB.
    """
    class FakeDB:
        def __init__(self, records):
            self._store = {r["id"]: r.copy() for r in records}

        def get(self, record_id: str) -> dict | None:
            return self._store.get(record_id)

        def put(self, record: dict) -> None:
            self._store[record["id"]] = record.copy()

        def delete(self, record_id: str) -> bool:
            return self._store.pop(record_id, None) is not None

        def all(self) -> list[dict]:
            return list(self._store.values())

    yield FakeDB(initial_records)

# Usage
with isolated_filesystem(seed_files={"config.json": json.dumps({"debug": True})}) as fs:
    config_path = os.path.join(fs, "config.json")
    # agent operates on config_path — no real files at risk
    pass
